## Cursor-Based Pagination Implementation

```javascript
// ─── Cursor Helpers ──────────────────────────────────────────────────────────

/**
 * Encode a (created_at, id) pair into an opaque, URL-safe cursor string.
 *
 * base64url (RFC 4648 §5) is used instead of standard base64 so the cursor
 * can be dropped directly into a query-string value without percent-encoding
 * the `+`, `/`, and `=` characters that standard base64 produces.
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({ created_at, id });
    return Buffer.from(payload).toString('base64url');
}

/**
 * Decode and validate a cursor string.
 *
 * Returns a validated { created_at, id } object, or null if the cursor is
 * missing, malformed, or contains unexpected field types.  Callers must treat
 * a null return as a 400 Bad Request — never silently ignore it.
 *
 * @param {string} cursor
 * @returns {{ created_at: string, id: number } | null}
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        const { created_at, id } = parsed;

        // Reject cursors that are missing fields or carry obviously wrong types.
        if (
            typeof created_at !== 'string'   ||   // must be an ISO timestamp string
            id == null                        ||   // null / undefined not allowed
            isNaN(new Date(created_at).getTime())  // must parse as a real date
        ) {
            return null;
        }

        return { created_at, id };
    } catch {
        // JSON.parse threw, Buffer.from threw, or anything else unexpected.
        return null;
    }
}

// ─── Endpoint ────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ──────────────────────────────────────────
    const limit = Math.min(parseInt(req.query.limit, 10) || 20, 100); // hard cap at 100

    let cursorData = null;
    if (req.query.after) {
        cursorData = decodeCursor(req.query.after);
        if (cursorData === null) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // ── 2. Fetch limit+1 rows (the N+1 trick) ───────────────────────────────
    //
    // Requesting one extra row lets us detect whether a next page exists
    // without a separate COUNT query.  We never return that extra row to
    // the client — it is a sentinel only.
    //
    // Sort is: created_at DESC, id DESC.
    // "After cursor" means rows that come *later* in that order, i.e. rows
    // with a strictly smaller (created_at, id) pair — hence the `<` comparison.
    //
    // PostgreSQL's row-value expression  (a, b) < (x, y)  expands to:
    //   a < x  OR  (a = x AND b < y)
    // which is exactly the semantics we need for a compound DESC sort.
    let result;

    if (cursorData) {
        // Pages 2, 3, 4 … — filter relative to the cursor position.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursorData.created_at, cursorData.id, limit + 1],
        );
    } else {
        // First page — no cursor filter at all.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1],
        );
    }

    // ── 3. Apply the N+1 sentinel logic ─────────────────────────────────────
    const rows    = result.rows;
    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows; // drop the sentinel

    // ── 4. Build the next cursor from the last row we are *returning* ────────
    //
    // The cursor always points at the last visible row so the next request
    // knows exactly where to continue.
    const lastPost   = posts[posts.length - 1];           // undefined when posts is empty
    const nextCursor = hasMore && lastPost
        ? encodeCursor(lastPost.created_at, lastPost.id)
        : null;

    // ── 5. Respond ───────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null on the final page or an empty result set
            limit,
        },
    });
}
```

---

### How to paginate through results (client side)

```
GET /api/posts?limit=20              ← first page (no cursor)
GET /api/posts?limit=20&after=<nextCursor from page 1>
GET /api/posts?limit=20&after=<nextCursor from page 2>
…
```

When `hasMore` is `false` (or `nextCursor` is `null`), you have reached the last page.

---

## Why cursor-based pagination is superior here

| Concern | Offset-based | Cursor-based |
|---|---|---|
| **Consistency** | A new post inserted between page 1 and page 2 shifts every row's offset, causing **duplicates or skipped rows** across pages | The cursor is pinned to a specific row; new inserts never displace already-seen results |
| **Performance at depth** | `OFFSET 10000` forces the database to **scan and discard** 10,000 rows before returning anything — cost grows linearly with depth | The `WHERE (created_at, id) < (…)` clause lets the index **seek directly** to the right position; cost is constant regardless of depth |
| **No COUNT overhead** | `SELECT COUNT(*)` scans the entire table (or a large index range) on every request — extremely expensive on large tables | Dropped entirely; `hasMore` is derived for free from the N+1 trick |
| **Stable under concurrent writes** | Rows moving around invalidate page numbers | The compound `(created_at, id)` cursor is stable because `id` is a unique tiebreaker, so sort order is deterministic even when two posts share the same timestamp |

The one genuine trade-off: clients **cannot jump to an arbitrary page number** (e.g., "go to page 47"). Cursor pagination is a linked list, not an array. For a public content feed — where "next page" is the only navigation primitive that matters — this is the right trade-off to make.

